      "n": 2,
      "column": "left",
      "text": "Tad leeż tavu Austi us\ṅudribu klantht/ un greeftawn\nSirdi us Sapraſchanu."
    },
    {
      "n": 3,
      "column": "left",
      "text": "Jo ja tu par to Sapra-\nſchanu lubgti/ un tavu Balti\npazelfi pehz Nopratchanas."
    },
    {
      "n": 4,
      "column": "left",
      "text": "Ja tu winnu mekle ka\nSudrabu/ un winnai pakkatdsih-\nfees ka apſlehtahm Mantahm."
    },
    {
      "n": 5,
      "column": "left",
      "text": "Tad taprattifi tu ta KUN-\nGA Bibjaschanu/ un atraffi to\nDeewa Atsifschannu."
    },
    {
      "n": 6,
      "column": "left",
      "text": "Jo tas KUNG S dohd\nGudribu: No winna Muttes\nnahk Atsifschana un Nopra-\nſchana."
    },
    {
      "n": 7,
      "column": "left",
      "text": "Wiſch paſarga teem Taif-\nneem weenu pastahwigu Buh-\nſchann/ un irr par preekſchtur-\nramahm Brunnahm teem/ kas\nbes Wainas staiga."
    },
    {
      "n": 8,
      "column": "left",
      "text": "Ka tee tahs Teefas Zeltus\nfarga/ un to Zeltu tawo Sweh-\nto wiſch paſarga."
    },
    {
      "n": 9,
      "column": "left",
      "text": "Tad faſprattifi tu Taifni-\nbu un Teefu/ un pareisag Lee-\ntas un wiſtu labbu Zeltu."
    },
    {
      "n": 10,
      "column": "left",
      "text": "Kata Gudriba tawa Sir-\ndi nahks/ un ta Sinnaschana\ntawai Dwchſelei mihlga buhs."
    },
    {
      "n": 11,
      "column": "left",
      "text": "Tad turrehs labs Pa-\ndohms pahr tew Wakti/ un\nSapraſchana tewi paglabbahs."
    },
    {
      "n": 12,
      "column": "left",
      "text": "Ka ta tew iſglabhs no\nta kauna Zelta/ no ta Wihra/"
    },
    {
      "n": 13,
      "column": "right",
      "text": "(lio teem)/ kas no te\nZelteem tahs Skaidribas no\natsittahs/ un staiga us Zelte-\ntahs Tuinfibas."
    },
    {
      "n": 14,
      "column": "right",
      "text": "Kas preezajahs Lau-\ndarriht/ un lihgjinojahs eef\npawehtitahm blehdigahm E-\ntahm."
    },
    {
      "n": 15,
      "column": "right",
      "text": "Kuru Zelti pahrwehr-\nirr/ un kas us fawahm Tekka-\nmaldahs."
    },
    {
      "n": 16,
      "column": "right",
      "text": "Ka tu iſglabhts tohvi\nfweschas Seewas/ kas tew\npeederr/ kas lipnigus Wahrd-\ndohd."
    },
    {
      "n": 17,
      "column": "right",
      "text": "Kas atstahj to * Wal-\ntajit fawas Jaunibas/ un ai\nmirst to Derribu fawa Deewa.\n* Tas irr : Sawu laulata Draugu, ko wi-\nma janna buhdama apsehmufi."
    },
    {
      "n": 18,
      "column": "right",
      "text": "Jo winnas Nains lo-\nkahs pee Nahwes/ un winna\nGabjumi us teem Pasudd-\nscheim."
    },
    {
      "n": 19,
      "column": "right",
      "text": "Wiſsi/ kas pee tahs ee-\neet/ ne greeſjeeſ atpaklat/ ned-\nattiks tohs Zeltus tahs Dsihw-\nbas."
    },
    {
      "n": 20,
      "column": "right",
      "text": "Tà ka tu staigahrt war-\nus to Zeltu to Labbo/ un fargah-\nwarri to Taifno Tekkas."
    },
    {
      "n": 21,
      "column": "right",
      "text": "Jo tee Rahmee eckſc-\ntahs Seimmes dſihwohs/ un-\ntee Sirds-Skaidree eekſch tah-\npalks."
    },
    {
      "n": 22,
      "column": "right",
      "text": "Bet tee Besdeewig-\ntaps no Semines isdelleti/ un-\ntee/ kas Tizzibu ne turr/ tap-\nno tahs isfatnoti."
    }
